-{"id":"charmed_rust-5ysf","title":"Integrate BubbleTea for TUI over SSH","description":"# Integrate BubbleTea for TUI over SSH

## Objective
Enable serving BubbleTea TUI applications over SSH connections, allowing interactive terminal applications to be accessed remotely.

## Implementation Details

### SSH-aware BubbleTea Program
```rust
use bubbletea::{Program, Model, Cmd};

/// Adapter that connects BubbleTea to SSH session I/O
pub struct SshProgram<M: Model> {
    program: Program<M>,
    session: Arc<Mutex<TerminalSession>>,
    channel: ChannelId,
}

impl<M: Model> SshProgram<M> {
    pub fn new(
        model: M,
        session: Arc<Mutex<TerminalSession>>,
        channel: ChannelId,
    ) -> Self {
        let program = Program::new(model);
        Self { program, session, channel }
    }

    pub async fn run(&mut self, handle: &mut russh::server::Handle) -> Result<(), WishError> {
        // Get initial window size
        let size = {
            let session = self.session.lock().await;
            session.window_size
        };

        // Initialize program with size
        self.program.set_window_size(size.cols, size.rows);

        // Render initial view
        let view = self.program.view();
        handle.data(self.channel, view.into()).await?;

        log::info!("BubbleTea program started on channel {}", self.channel);
        Ok(())
    }
}
```

### SSH Input Adapter
```rust
/// Converts SSH input to BubbleTea messages
pub struct SshInputAdapter {
    parser: vt_input::Parser,
}

impl SshInputAdapter {
    pub fn new() -> Self {
        Self { parser: vt_input::Parser::new() }
    }

    pub fn parse(&mut self, data: &[u8]) -> Vec<KeyMsg> {
        let mut messages = Vec::new();

        for event in self.parser.parse(data) {
            match event {
                vt_input::Event::Key(key) => {
                    messages.push(self.convert_key(key));
                }
                vt_input::Event::Mouse(mouse) => {
                    messages.push(KeyMsg::Mouse(mouse.into()));
                }
                _ => {}
            }
        }

        messages
    }
}
```

### SSH Output Renderer
```rust
/// Renders BubbleTea output to SSH channel
pub struct SshRenderer {
    channel: ChannelId,
    handle: russh::server::Handle,
    alt_screen: bool,
}

impl SshRenderer {
    pub async fn render(&mut self, view: &str) -> Result<(), WishError> {
        // Enter alt screen if not already
        if !self.alt_screen {
            self.handle.data(self.channel, "\x1b[?1049h".into()).await?;
            self.alt_screen = true;
        }

        // Clear and render
        let output = format!("\x1b[H\x1b[2J{}", view);
        self.handle.data(self.channel, output.into()).await?;

        log::debug!("Rendered {} bytes to channel {}", output.len(), self.channel);
        Ok(())
    }

    pub async fn cleanup(&mut self) -> Result<(), WishError> {
        if self.alt_screen {
            self.handle.data(self.channel, "\x1b[?1049l".into()).await?;
            self.alt_screen = false;
        }
        Ok(())
    }
}
```

### Handler Integration
```rust
impl Handler for ConnectionHandler {
    async fn shell_request(
        &mut self,
        channel: ChannelId,
        session: &mut Session,
    ) -> Result<(), Self::Error> {
        log::info!("Shell request on channel {}", channel);

        // Get the BubbleTea app factory
        if let Some(app_factory) = &self.app_factory {
            let model = app_factory.create(&self.context);
            let program = SshProgram::new(model, self.session.clone(), channel);

            // Spawn the program runner
            let handle = session.handle();
            tokio::spawn(async move {
                if let Err(e) = program.run(&mut handle).await {
                    log::error!("BubbleTea program error: {}", e);
                }
            });

            session.request_success();
        } else {
            log::warn!("No app factory configured");
            session.request_failure();
        }

        Ok(())
    }

    async fn data(
        &mut self,
        channel: ChannelId,
        data: &[u8],
        session: &mut Session,
    ) -> Result<(), Self::Error> {
        // Parse input and send to BubbleTea
        let messages = self.input_adapter.parse(data);
        for msg in messages {
            self.program.send(msg);
        }
        Ok(())
    }
}
```

### Server Builder Pattern
```rust
impl Server {
    pub fn with_bubbletea<M, F>(mut self, factory: F) -> Self
    where
        M: Model + 'static,
        F: Fn(&Context) -> M + Send + Sync + 'static,
    {
        self.app_factory = Some(Box::new(move |ctx| Box::new(factory(ctx))));
        self
    }
}

// Usage example
let server = Server::new(config)
    .with_bubbletea(|ctx| MyTuiApp::new(ctx.user.clone()))
    .with_auth(my_auth_handler);
```

