}

impl WishServer {
    pub fn new(config: WishConfig) -> Result<Self> {
        let russh_config = Config {
            inactivity_timeout: Some(Duration::from_secs(config.timeout_secs)),
            auth_rejection_time: Duration::from_secs(3),
            auth_rejection_time_initial: Some(Duration::from_secs(0)),
            keys: vec![load_or_generate_host_key(&config.host_key_path)?],
            ..Default::default()
        };

        Ok(Self {
            config: Arc::new(russh_config),
            bind_addr: config.bind_addr,
        })
    }

    pub async fn run(&self) -> Result<()> {
        log::info!("Starting SSH server on {}", self.bind_addr);
        russh::server::run(self.config.clone(), &self.bind_addr, self).await?;
        Ok(())
    }
}
```

