```rust
// examples/counter/main.rs - BEFORE (manual)
use bubbletea::{Command, Model};

struct Counter {
    count: i32,
}

impl Model for Counter {
    type Message = Msg;

    fn init() -> (Self, Command<Msg>) {
        (Counter { count: 0 }, Command::none())
    }

    fn update(&mut self, msg: Msg) -> Command<Msg> {
        match msg {
            Msg::Increment => self.count += 1,
            Msg::Decrement => self.count -= 1,
            Msg::Quit => return Command::quit(),
        }
        Command::none()
    }

    fn view(&self) -> String {
        format!("Count: {}", self.count)
    }
}
```

```rust
// examples/counter/main.rs - AFTER (with derive)
use bubbletea::Command;
use bubbletea_macros::Model;

enum Msg {
    Increment,
    Decrement,
    Quit,
}

#[derive(Model)]
struct Counter {
    #[state]
    count: i32,
}

impl Counter {
    #[init]
    fn init() -> (Self, Command<Msg>) {
        (Counter { count: 0 }, Command::none())
    }

    #[update]
    fn update(&mut self, msg: Msg) -> Command<Msg> {
        match msg {
            Msg::Increment => self.count += 1,
            Msg::Decrement => self.count -= 1,
            Msg::Quit => return Command::quit(),
        }
        Command::none()
    }

    #[view]
    fn view(&self) -> String {
        format!("Count: {}\n\n[+/-] Change  [q] Quit", self.count)
    }
}

fn main() -> anyhow::Result<()> {
    bubbletea::run(Counter::init)
}
```

