```rust
// examples/derive_showcase/main.rs
//! Comprehensive example demonstrating all #[derive(Model)] features

use bubbletea::Command;
use bubbletea_macros::Model;
use lipgloss::{Color, Style};
use std::time::{Duration, Instant};

/// Application messages
#[derive(Debug, Clone)]
enum Msg {
    Tick,
    IncrementCounter,
    DecrementCounter,
    ToggleTimer,
    UpdateInput(String),
    Submit,
    Quit,
}

/// Main application model demonstrating all derive features
#[derive(Model)]
#[model(message = Msg)]  // Explicit message type
struct App {
    // Basic state field - triggers re-render on change
    #[state]
    counter: i32,

    // Another state field
    #[state]
    timer_running: bool,

    // State with custom equality (for floating point)
    #[state(eq = "duration_approx_eq")]
    elapsed: Duration,

    // Skipped state - changes don't trigger re-render
    #[state(skip)]
    last_tick: Option<Instant>,

    // Debug state - logs changes
    #[state(debug)]
    input_text: String,

    // Non-state field - never tracked
    styles: AppStyles,
}

/// Custom equality for Duration (ignore sub-millisecond differences)
fn duration_approx_eq(a: &Duration, b: &Duration) -> bool {
    a.as_millis() == b.as_millis()
}

struct AppStyles {
    title: Style,
    counter: Style,
    timer: Style,
}

impl Default for AppStyles {
